import React from 'react';
import { Pie } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend
} from 'chart.js';

ChartJS.register(ArcElement, Tooltip, Legend);

const DataInsightsPieChart = ({ data }) => {
  if (!Array.isArray(data) || data.length === 0) return null;

  // 🔥 AUTO detect label & value
  const keys = Object.keys(data[0]);
  const labelKey = keys.find(k => typeof data[0][k] === 'string');
  const valueKey = keys.find(k => typeof data[0][k] === 'number');

  if (!labelKey || !valueKey) return null;

  // 🔥 Remove duplicate labels
  const grouped = {};
  data.forEach(item => {
    const label = item[labelKey];
    const value = item[valueKey];
    grouped[label] = (grouped[label] || 0) + value;
  });

  const labels = Object.keys(grouped);
  const values = Object.values(grouped);

  const chartData = {
    labels,
    datasets: [
      {
        data: values,
        backgroundColor: [
          '#6366F1',
          '#22C55E',
          '#F97316',
          '#EF4444',
          '#14B8A6'
        ],
        borderColor: '#ffffff',
        borderWidth: 2
      }
    ]
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    cutout: '60%', // 🔥 donut style
    plugins: {
      legend: {
        position: 'top',
        align: 'center',
        labels: {
          boxWidth: 14,
          padding: 12,
          font: {
            size: 12,
            weight: '500'
          }
        }
      },
      tooltip: {
        backgroundColor: '#1f2937',
        padding: 10,
        cornerRadius: 6,
        callbacks: {
          label: (ctx) => `${ctx.label}: ${ctx.raw}`
        }
      }
    }
  };

  return <Pie data={chartData} options={options} />;
};

export default DataInsightsPieChart;
